patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..dc729c938c8f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1338,6 +1338,31 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

+  // Look through and with a mask on V1 or V2 for OR operations. This allows us
+  // to handle patterns like (x == C1) || ((x & Mask) == C2) where C1 + 1 == C2
+  // and Mask is a power-of-2 minus 1 (i.e., Mask = -2^n for some n).
+  // In this case, (x & Mask) == C2 represents the range [C2, C2 + ~Mask].
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  if (!IsAnd && V1 != V2) {
+    Value *X;
+    // Check if V1 is (X & Mask1) and V2 is X
+    if (match(V1, m_And(m_Value(X), m_APInt(Mask1))) && X == V2) {
+      if (auto *AndInst = dyn_cast<Instruction>(V1);
+          AndInst && AndInst->hasOneUse())
+        V1 = X;
+      else
+        Mask1 = nullptr;
+    }
+    // Check if V2 is (X & Mask2) and V1 is X
+    else if (match(V2, m_And(m_Value(X), m_APInt(Mask2))) && X == V1) {
+      if (auto *AndInst = dyn_cast<Instruction>(V2);
+          AndInst && AndInst->hasOneUse())
+        V2 = X;
+      else
+        Mask2 = nullptr;
+    }
+  }
+
   if (V1 != V2)
     return nullptr;

@@ -1351,6 +1376,30 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

+  // If we have a masked comparison in an OR operation, expand the range to
+  // include all values that would satisfy the masked comparison.
+  // For (x & Mask) == C, this is the range [C, C + ~Mask] if C is aligned
+  // to the mask (i.e., C & ~Mask == 0).
+  if (!IsAnd && Mask1 && Pred1 == ICmpInst::ICMP_EQ) {
+    APInt Mask = *Mask1;
+    APInt NotMask = ~Mask;
+    if ((*C1 & Mask) == *C1) {
+      // The range is [C1, C1 + NotMask + 1)
+      APInt Lower = *C1;
+      APInt Upper = *C1 + NotMask + 1;
+      CR1 = ConstantRange(Lower, Upper);
+    }
+  }
+  if (!IsAnd && Mask2 && Pred2 == ICmpInst::ICMP_EQ) {
+    APInt Mask = *Mask2;
+    APInt NotMask = ~Mask;
+    if ((*C2 & Mask) == *C2) {
+      APInt Lower = *C2;
+      APInt Upper = *C2 + NotMask + 1;
+      CR2 = ConstantRange(Lower, Upper);
+    }
+  }
+
   Type *Ty = V1->getType();
   Value *NewV = V1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);

